const items = $input.all();
const normalized = [];

for (const item of items) {
  const raw = item.json;

  // Extract salary from title/description
  const salaryMatch = (raw.title + ' ' + (raw.contentSnippet || '')).match(/(\d+)k?\s*[-–]\s*(\d+)k?\s*€/);
  let salaryMin = null, salaryMax = null;
  if (salaryMatch) {
    salaryMin = parseInt(salaryMatch[1]) * (salaryMatch[1].length <= 2 ? 1000 : 1);
    salaryMax = parseInt(salaryMatch[2]) * (salaryMatch[2].length <= 2 ? 1000 : 1);
  }

  // Detect contract type
  const text = (raw.title + ' ' + (raw.contentSnippet || '')).toLowerCase();
  let contract_type = 'cdi';
  if (text.includes('alternance') || text.includes('apprentissage')) contract_type = 'alternance';
  else if (text.includes('stage') || text.includes('internship')) contract_type = 'stage';
  else if (text.includes('cdd')) contract_type = 'cdd';
  else if (text.includes('freelance')) contract_type = 'freelance';

  // Detect remote
  let remote = 'none';
  if (text.includes('full remote') || text.includes('100% remote') || text.includes('télétravail complet')) remote = 'full';
  else if (text.includes('hybrid') || text.includes('hybride') || text.includes('télétravail partiel')) remote = 'hybrid';

  // Extract skills
  const skillKeywords = ['python','javascript','typescript','react','docker','kubernetes',
    'fastapi','django','aws','gcp','azure','postgresql','redis','llm','rag',
    'langchain','ollama','machine learning','devops','ci/cd','linux','n8n','c#','java'];
  const requiredSkills = skillKeywords.filter(s => text.includes(s));

  // Experience level
  let experience_level = 'junior';
  if (text.includes('senior') || text.includes('5 ans') || text.includes('5 years')) experience_level = 'senior';
  else if (text.includes('confirmé') || text.includes('3 ans') || text.includes('mid')) experience_level = 'mid';

  // Language detection
  const frMarkers = ['nous recherchons','poste','entreprise','expérience','compétences','rejoindre'];
  const language = frMarkers.some(m => text.includes(m)) ? 'fr' : 'en';

  normalized.push({
    json: {
      source: 'indeed',
      source_id: raw.guid || raw.link,
      url: raw.link || raw.guid,
      title: raw.title || '',
      company_name: raw.creator || raw['dc:creator'] || 'Unknown',
      location: raw.location || 'Lyon',
      contract_type,
      salary_min: salaryMin,
      salary_max: salaryMax,
      remote,
      required_skills: requiredSkills,
      experience_level,
      language,
      description: raw.contentSnippet || raw.content || '',
      published_at: raw.isoDate || raw.pubDate || new Date().toISOString(),
      scraped_at: new Date().toISOString()
    }
  });
}

return normalized;

// Deterministic scorer — no LLM
const items = $input.all();

// Hardcoded profile for now — Phase 1
// Will be replaced by DB lookup in Phase 2
const profile = {
  target_roles: ['AI Engineer', 'LLM Engineer', 'ML Engineer', 'DevOps Engineer'],
  avoid_roles: ['Data Analyst', 'Support Engineer', 'Helpdesk'],
  skills: ['python', 'docker', 'llm', 'rag', 'fastapi', 'postgresql', 'c#', 'linux'],
  salary_min: 38000,
  salary_target: 45000,
  remote_preference: true,
  cities: ['lyon', 'paris', 'grenoble'],
  countries: ['france'],
  contract_types: ['alternance', 'cdi'],
  experience_level: 'junior'
};

const CONFIDENCE_THRESHOLD = 40;
const SCORE_THRESHOLD = 40;

function scoreJob(job, profile) {
  // 1. Skill match (30pts)
  const required = new Set(job.required_skills.map(s => s.toLowerCase()));
  const userSkills = new Set(profile.skills.map(s => s.toLowerCase()));
  let skillMatch = 0;
  if (required.size === 0) {
    skillMatch = 15;
  } else {
    const matched = [...required].filter(s => userSkills.has(s)).length;
    skillMatch = Math.round((matched / required.size) * 30);
  }

  // 2. Experience match (20pts)
  const levelMap = { junior: 1, mid: 2, senior: 3 };
  const jobLevel = levelMap[job.experience_level] || 1;
  const userLevel = levelMap[profile.experience_level] || 1;
  const diff = Math.abs(jobLevel - userLevel);
  const experienceMatch = diff === 0 ? 20 : diff === 1 ? 10 : 0;

  // 3. Location (15pts)
  const jobLocation = (job.location || '').toLowerCase();
  let locationScore = 0;
  if (job.remote === 'full' && profile.remote_preference) locationScore = 15;
  else if (profile.cities.some(c => jobLocation.includes(c))) locationScore = 15;
  else if (profile.countries.some(c => jobLocation.includes(c))) locationScore = 8;
  else if (job.remote === 'hybrid') locationScore = 6;

  // 4. Salary (15pts)
  let salaryScore = 7; // unknown = half
  if (job.salary_min || job.salary_max) {
    const mid = ((job.salary_min || 0) + (job.salary_max || job.salary_min || 0)) / 2;
    if (mid >= profile.salary_target) salaryScore = 15;
    else if (mid >= profile.salary_min) salaryScore = Math.round(((mid - profile.salary_min) / (profile.salary_target - profile.salary_min + 1)) * 15);
    else salaryScore = 0;
  }

  // 5. Contract (10pts)
  const contractScore = profile.contract_types.includes(job.contract_type) ? 10 : 0;

  // 6. Company (5pts) — default 50 quality for now
  const companyScore = Math.round((50 / 100) * 5);

  // 7. Freshness (5pts)
  let freshnessScore = 2;
  if (job.published_at) {
    const ageDays = (Date.now() - new Date(job.published_at).getTime()) / (1000 * 60 * 60 * 24);
    if (ageDays <= 2) freshnessScore = 5;
    else if (ageDays <= 7) freshnessScore = 3;
    else if (ageDays <= 14) freshnessScore = 1;
    else freshnessScore = 0;
  }

  const total = skillMatch + experienceMatch + locationScore + salaryScore + contractScore + companyScore + freshnessScore;

  // Extraction confidence
  const fields = ['required_skills', 'experience_level', 'salary_min', 'location', 'contract_type'];
  const filled = fields.filter(f => {
    const v = job[f];
    return v !== null && v !== undefined && v !== '' && !(Array.isArray(v) && v.length === 0);
  }).length;
  const confidence = Math.round((filled / fields.length) * 100);

  // Avoid roles check
  const titleLower = job.title.toLowerCase();
  const avoided = profile.avoid_roles.some(r => titleLower.includes(r.toLowerCase()));

  return {
    skill_match: skillMatch,
    experience_match: experienceMatch,
    location_score: locationScore,
    salary_score: salaryScore,
    contract_score: contractScore,
    company_score: companyScore,
    freshness_score: freshnessScore,
    total,
    extraction_confidence: confidence,
    needs_review: total >= 60 && confidence < 60,
    avoided
  };
}

const results = [];
for (const item of items) {
  const job = item.json;
  const score = scoreJob(job, profile);

  // Auto-archive if avoided role or score too low
  let status = 'found';
  if (score.avoided || score.total < SCORE_THRESHOLD) status = 'archived';
  else if (score.total >= 70) status = 'shortlisted';

  results.push({
    json: {
      ...job,
      score,
      status
    }
  });
}

return results;

